// data/boss.js — GENERATED by pipeline/build-boss.js. DO NOT EDIT BY HAND.
// Per-branch "boss" discrimination vignettes for the learning path (window.BOSSES[branchId]).
window.BOSSES = {"antidepressants":[{"id":"boss_antidepressants_1","stem":"A 46-year-old with treatment-resistant depression is about to start an oral MAO inhibitor, but he travels constantly for work, eats most meals in restaurants, and admits he cannot reliably follow a strict low-tyramine diet. You want the oral agent with the lowest risk of a tyramine-triggered hypertensive crisis and the shortest washout on stopping. Which agent do you choose?","options":["Moclobemide","Phenelzine","Tranylcypromine","Selegiline"],"answer":"Moclobemide","explanation":"Moclobemide is a Reversible Inhibitor of MAO-A (RIMA): dietary tyramine can competitively displace it from the enzyme, so no strict low-tyramine diet is required, and its very short half-life gives a far shorter washout than the irreversible drugs. Phenelzine and tranylcypromine are irreversible, non-selective MAOIs that mandate strict tyramine restriction and a ~2-week washout while new MAO is synthesized. Oral selegiline at antidepressant doses loses its MAO-B selectivity and also inhibits MAO-A, reinstating the tyramine diet (only the low-dose 6 mg/24h transdermal patch bypasses gut MAO-A and spares the diet).","meds":["moclobemide","phenelzine","tranylcypromine","selegiline"],"focus":"MAOI tyramine diet/washout — reversible MAO-A (RIMA) vs irreversible MAOIs","tags":["comparison"],"source":{"name":"MAOI product monographs (moclobemide RIMA; phenelzine/tranylcypromine irreversible; selegiline dose-dependent MAO-A)","origin":"monograph"},"answerId":"moclobemide"},{"id":"boss_antidepressants_2","stem":"A patient with schizophrenia stabilized on clozapine develops a comorbid major depressive episode with prominent obsessive-compulsive features, and you plan to add an SSRI. Clozapine is cleared largely by CYP1A2. Which SSRI is the most likely to precipitate clozapine toxicity (over-sedation, seizures, rising clozapine level) through enzyme inhibition?","options":["Fluvoxamine","Sertraline","Escitalopram","Citalopram"],"answer":"Fluvoxamine","explanation":"Fluvoxamine is a potent CYP1A2 (and CYP2C19) inhibitor — the most interaction-prone SSRI — and sharply raises clozapine levels, risking sedation, seizures and other dose-related toxicity. Sertraline, escitalopram and citalopram are only weak-to-mild CYP inhibitors with clean interaction profiles, so they are far safer to combine with clozapine. The discriminator is the CYP1A2 burden, not serotonergic potency, which is comparable across the four.","meds":["fluvoxamine","sertraline","escitalopram","citalopram"],"focus":"CYP1A2 inhibition (fluvoxamine) raising clozapine/theophylline levels","tags":["comparison"],"source":{"name":"Fluvoxamine label — potent CYP1A2/2C19 inhibition (clozapine interaction)","origin":"openfda"},"answerId":"fluvoxamine"},{"id":"boss_antidepressants_3","stem":"A 24-year-old woman with major depression and a current history of bulimia nervosa (recurrent self-induced purging) asks for an antidepressant. Which agent is explicitly contraindicated in this patient because it lowers the seizure threshold and produced a higher incidence of seizures in patients with eating disorders?","options":["Bupropion","Fluoxetine","Sertraline","Mirtazapine"],"answer":"Bupropion","explanation":"Bupropion is contraindicated in a current or prior diagnosis of bulimia or anorexia nervosa (and in seizure disorders) because a higher seizure incidence was seen in these patients — a dose-dependent seizure-threshold effect. Fluoxetine is, in contrast, the antidepressant of choice in bulimia; sertraline and mirtazapine carry no eating-disorder contraindication. The discriminating axis is the seizure-threshold/eating-disorder contraindication unique to bupropion, not antidepressant efficacy.","meds":["bupropion","fluoxetine","sertraline","mirtazapine"],"focus":"Seizure threshold / eating-disorder (bulimia-anorexia) contraindication — bupropion","tags":["comparison"],"source":{"name":"Bupropion XL label — contraindications (bulimia/anorexia, seizure disorder)","origin":"openfda"},"answerId":"bupropion"},{"id":"boss_antidepressants_4","stem":"A 70-year-old man with major depression has lost 6 kg from poor appetite, has severe initial insomnia, and previously stopped an SSRI because of persistent nausea and sexual dysfunction. Which antidepressant best targets his appetite loss and insomnia while being least likely to add nausea or sexual dysfunction?","options":["Mirtazapine","Bupropion","Sertraline","Venlafaxine"],"answer":"Mirtazapine","explanation":"Mirtazapine is a presynaptic α2-antagonist whose potent H1 antihistamine effect plus 5-HT2 and 5-HT3 blockade produce sedation, increased appetite/weight gain and an antiemetic effect, with lower sexual dysfunction than SSRIs — an ideal match for depression with insomnia, weight loss and prior SSRI GI/sexual intolerance. Bupropion is activating and tends to cause weight loss and insomnia (the opposite of what is needed); sertraline characteristically causes diarrhea/nausea and sexual dysfunction; venlafaxine causes nausea, insomnia and sexual dysfunction.","meds":["mirtazapine","bupropion","sertraline","venlafaxine"],"focus":"Mirtazapine appetite/sedation/weight-gain niche (α2 antagonist + H1, low sexual dysfunction)","tags":["comparison"],"source":{"name":"Mirtazapine monograph — H1 antihistamine and 5-HT2/5-HT3 effects (appetite, sedation, antiemetic)","origin":"monograph"},"answerId":"mirtazapine"},{"id":"boss_antidepressants_5","stem":"A patient with treatment-resistant major depression and acute suicidal ideation needs an antidepressant effect within hours to a day rather than the usual weeks. The chosen agent must be given in a certified clinic with at least two hours of post-dose monitoring for sedation, dissociation and blood-pressure rise under a restricted (REMS) distribution program, alongside an ongoing oral antidepressant. Which agent fits?","options":["Esketamine","Venlafaxine","Mirtazapine","Tranylcypromine"],"answer":"Esketamine","explanation":"Intranasal esketamine is an NMDA-glutamate receptor antagonist with rapid onset (hours to about one day), indicated for treatment-resistant depression and MDD with acute suicidality; it is available only through a REMS program requiring in-clinic administration with ≥2 hours of monitoring for sedation, dissociation and transient BP elevation, and is always paired with an oral antidepressant. Venlafaxine, mirtazapine and tranylcypromine are oral monoaminergic agents with the usual 2–6 week onset lag and no supervised-dosing/REMS requirement.","meds":["esketamine","venlafaxine","mirtazapine","tranylcypromine"],"focus":"Rapid-onset glutamatergic NMDA antagonist with REMS/supervised in-clinic dosing — esketamine","tags":["comparison"],"source":{"name":"Esketamine (SPRAVATO) label — boxed warning/REMS, rapid onset, NMDA MOA","origin":"monograph"},"answerId":"esketamine"}],"antipsychotics":[{"id":"boss_antipsychotics_1","stem":"A 29-year-old man with schizophrenia is still floridly psychotic after two successive antipsychotic trials, each at an adequate dose for 8 weeks with pharmacy-confirmed adherence. His team wants the single agent with proven superiority for this presentation and accepts that it obligates registry-enforced blood-count monitoring. Which antipsychotic is indicated?","options":["Clozapine","Olanzapine","Risperidone","Quetiapine"],"answer":"Clozapine","explanation":"Two failed adequate antipsychotic trials define treatment-resistant schizophrenia, and clozapine is the ONLY antipsychotic proven superior in this exact scenario (and the only one shown to reduce suicidality). Because of agranulocytosis it uniquely mandates registry ANC monitoring — weekly for 6 months, then every 2 weeks to 12 months, then every 4 weeks. Olanzapine, risperidone and quetiapine are all reasonable general choices but none is a treatment-resistance-specific agent and none carries mandatory blood-count surveillance; selecting one here simply repeats a strategy that has already failed.","meds":["clozapine","olanzapine","risperidone","quetiapine"],"focus":"treatment-resistant schizophrenia / clozapine ANC monitoring","tags":["comparison"],"source":{"name":"Clozapine monograph (boxed warning; ANC monitoring schedule)","origin":"monograph"},"answerId":"clozapine"},{"id":"boss_antipsychotics_2","stem":"A 22-year-old man with a first episode of schizophrenia already has obesity, impaired fasting glucose and a strong family history of type 2 diabetes. His psychiatrist wants the antipsychotic least likely to worsen his weight, glucose and lipids. Which is the best metabolic choice among these options?","options":["Lurasidone","Olanzapine","Quetiapine","Risperidone"],"answer":"Lurasidone","explanation":"Lurasidone has minimal H1 and muscarinic activity, making it weight-, lipid- and glucose-favourable with low prolactin — the metabolically safest of these four. Olanzapine is among the two worst SGAs metabolically (marked weight gain, dyslipidemia, hyperglycemia/DKA), quetiapine carries moderate metabolic risk, and risperidone is intermediate. In a metabolically vulnerable patient lurasidone best protects weight and glucose (ziprasidone and aripiprazole would be comparably favourable but are not offered here).","meds":["lurasidone","olanzapine","quetiapine","risperidone"],"focus":"metabolic syndrome risk (lowest among SGAs)","tags":["comparison"],"source":{"name":"Lurasidone monograph (metabolically favourable profile)","origin":"monograph"},"answerId":"lurasidone"},{"id":"boss_antipsychotics_3","stem":"A 41-year-old woman with schizophrenia needs an antipsychotic, but her baseline ECG shows a QTc of 480 ms and she is also maintained on methadone; her electrolytes are being optimized. The team wants to AVOID the agent most likely to prolong her QT interval further. Which antipsychotic should be avoided here?","options":["Ziprasidone","Aripiprazole","Lurasidone","Brexpiprazole"],"answer":"Ziprasidone","explanation":"Ziprasidone produces the greatest QT prolongation of the SGAs — its defining caution, with torsades risk that mandates avoiding other QT-prolonging drugs and correcting electrolytes — so it is exactly the wrong choice in a patient with QTc 480 ms on methadone. Aripiprazole and brexpiprazole have no notable QT signal, and lurasidone is low-QT risk; all three are far safer cardiac choices here. The discrimination is recognizing ziprasidone as the QT outlier.","meds":["ziprasidone","aripiprazole","lurasidone","brexpiprazole"],"focus":"QTc prolongation (greatest among the options)","tags":["comparison"],"source":{"name":"Ziprasidone monograph (greatest QT prolongation of the SGAs)","origin":"monograph"},"answerId":"ziprasidone"},{"id":"boss_antipsychotics_4","stem":"A 34-year-old man with schizophrenia has well-controlled positive symptoms but disabling, persistent negative symptoms — flat affect, anhedonia and amotivation — despite good adherence. His psychiatrist wants the antipsychotic whose D3-preferring partial agonism is specifically theorized to benefit negative symptoms. Which agent best fits?","options":["Cariprazine","Aripiprazole","Brexpiprazole","Risperidone"],"answer":"Cariprazine","explanation":"Cariprazine is the most D3-selective antipsychotic — a D3-preferring D2/D3 partial agonist whose D3 preference is theorized to benefit negative symptoms and anhedonia. Aripiprazole and brexpiprazole are also D2/D3 partial agonists, but neither is D3-preferring. Risperidone is a full D2 antagonist — in fact the most D2-potent SGA, with high EPS and hyperprolactinemia — and offers no negative-symptom advantage. The D3 preference is what singles out cariprazine among the partial agonists.","meds":["cariprazine","aripiprazole","brexpiprazole","risperidone"],"focus":"partial agonism (D3-preferring, negative symptoms)","tags":["comparison"],"source":{"name":"Cariprazine monograph (D3-preferring D2/D3 partial agonism)","origin":"monograph"},"answerId":"cariprazine"},{"id":"boss_antipsychotics_5","stem":"A 24-year-old man with schizophrenia needs a first-generation antipsychotic but has already had two acute dystonic reactions and severe akathisia on previous agents. The team is willing to accept sedation and orthostasis in exchange for the lowest possible risk of further extrapyramidal reactions. Which first-generation antipsychotic has the lowest extrapyramidal liability?","options":["Chlorpromazine","Haloperidol","Fluphenazine","Perphenazine"],"answer":"Chlorpromazine","explanation":"Chlorpromazine is the prototype LOW-potency FGA: its strong H1, muscarinic and α1 blockade brings sedation, anticholinergic effects and orthostasis but comparatively LESS EPS than high-potency agents — the right trade-off for an EPS-prone patient. Haloperidol and fluphenazine are high-potency agents with maximal EPS and minimal sedation, precisely what caused this patient's dystonia and akathisia. Perphenazine is mid-potency with intermediate (still greater than chlorpromazine) EPS. Lower potency buys the least extrapyramidal risk at the cost of autonomic burden.","meds":["chlorpromazine","haloperidol","fluphenazine","perphenazine"],"focus":"FGA potency (EPS vs sedation/anticholinergic/orthostasis trade-off)","tags":["comparison"],"source":{"name":"First-generation antipsychotic potency comparison (EPS vs autonomic burden)","origin":"monograph"},"answerId":"chlorpromazine"}],"mood":[{"id":"boss_mood_1","stem":"A 46-year-old woman with bipolar I disorder, stable for years on a single maintenance mood stabilizer, strains her back and starts taking ibuprofen around the clock for two weeks. She now presents with a coarse tremor, ataxia, slurred speech, vomiting, and confusion. Which maintenance agent's rising serum concentration best explains this picture, given that it is renally excreted (not metabolized) and has a narrow therapeutic index?","options":["Valproate","Lithium","Carbamazepine","Lamotrigine"],"answer":"Lithium","explanation":"Lithium is renally excreted and NOT metabolized, so anything that lowers renal clearance — NSAIDs, thiazide diuretics, ACE inhibitors/ARBs, dehydration, or a low-sodium state — raises the level and precipitates toxicity. Its therapeutic range is narrow (0.6-1.2 mmol/L; toxicity begins >1.5, severe >2.0), so the sustained ibuprofen easily pushed her into the toxic range: coarse tremor, ataxia, dysarthria, vomiting, and confusion are the classic toxicity syndrome. Valproate is hepatically metabolized (glucuronidation/beta-oxidation), monitored at 350-700 umol/L, and is not driven into toxicity by an NSAID. Carbamazepine is CYP3A4-metabolized (4-12 ug/mL); its toxicity is driven by 3A4 inhibitors such as grapefruit juice, not by ibuprofen. Lamotrigine has no routine serum level and is cleared by glucuronidation, unaffected by NSAIDs.","meds":["valproate","lithium","carbamazepine","lamotrigine"],"focus":"therapeutic drug monitoring / renal excretion — narrow-index agent whose toxicity is precipitated by NSAIDs, thiazides, and dehydration","tags":["comparison"],"source":{"name":"Lithium product monograph (boxed warning: lithium toxicity)","origin":"monograph"},"answerId":"lithium"},{"id":"boss_mood_2","stem":"A 24-year-old woman with bipolar I disorder is not using contraception and hopes to conceive within the year. Reviewing her options for maintenance, you want to identify and avoid the mood stabilizer that carries the greatest fetal risk — the one associated with neural-tube defects, the lowest childhood IQ, and increased autism. Which agent should be avoided in someone who may become pregnant?","options":["Lamotrigine","Topiramate","Valproate","Carbamazepine"],"answer":"Valproate","explanation":"Valproate is the most teratogenic mood stabilizer: neural-tube defects (spina bifida), craniofacial and cardiac malformations, and dose-dependent neurodevelopmental harm including the LOWEST childhood IQ and increased autism — it is the classic agent to avoid in anyone who could become pregnant. Carbamazepine is also teratogenic (neural-tube defects, craniofacial/cardiac malformations) but overall less severe than valproate, particularly for neurodevelopment. Topiramate causes oral clefts and reduced fetal growth (and lowers oral-contraceptive efficacy), but it is not a first-line mood stabilizer and its risk profile is narrower than valproate's. Lamotrigine is the comparatively pregnancy-SAFER choice with no consistent major teratogenic signal and is often the preferred maintenance stabilizer around pregnancy.","meds":["lamotrigine","topiramate","valproate","carbamazepine"],"focus":"teratogenicity — the worst teratogen (NTDs, lowest IQ, autism) to avoid in reproductive-age patients","tags":["comparison"],"source":{"name":"Valproate product monograph (boxed warning; teratogenicity)","origin":"monograph"},"answerId":"valproate"},{"id":"boss_mood_3","stem":"A patient is started on a new agent for bipolar maintenance and depression. The psychiatrist stresses that the dose must be built up very slowly over about six weeks, must never be front-loaded, must be restarted from scratch after any gap longer than five days, and that co-prescribing one other mood stabilizer would force HALVING the dose. Two weeks after a rushed dose increase, the patient develops a spreading rash with painful oral mucosal erosions. Which drug was started?","options":["Carbamazepine","Oxcarbazepine","Valproate","Lamotrigine"],"answer":"Lamotrigine","explanation":"The mandated slow titration exists specifically to reduce the risk of Stevens-Johnson syndrome/TEN, and the risk climbs with fast titration or with valproate co-therapy — valproate inhibits glucuronidation and roughly DOUBLES the lamotrigine level, which is exactly why the dose must be halved when they are combined. The 'restart from scratch after a >5-day gap' rule and 'no routine serum level' are also lamotrigine hallmarks; the painful mucosal rash after a rushed increase is the feared SJS/TEN. Carbamazepine and oxcarbazepine can also cause HLA-B*1502-associated SJS/TEN, but neither is defined by this slow anti-rash titration schedule nor by the valproate 'halve-the-dose' interaction. Valproate is the interacting partner that doubles the level here, not the drug being titrated.","meds":["carbamazepine","oxcarbazepine","valproate","lamotrigine"],"focus":"SJS / slow titration — the agent whose slow up-titration prevents SJS/TEN and that valproate doubles","tags":["comparison"],"source":{"name":"Lamotrigine product monograph (boxed warning: serious skin rashes)","origin":"monograph"},"answerId":"lamotrigine"},{"id":"boss_mood_4","stem":"A 30-year-old woman taking a combined estrogen-progestin oral contraceptive is started on a mood stabilizer. At the one-month recheck her drug level has fallen below the therapeutic range despite confirmed good adherence, prompting a dose increase; three months later she reports an unplanned pregnancy. Which agent best explains BOTH the self-lowering serum level and the contraceptive failure?","options":["Lithium","Carbamazepine","Lamotrigine","Valproate"],"answer":"Carbamazepine","explanation":"Carbamazepine autoinduces — it accelerates its own metabolism over the first 2-4 weeks, so the level drops and it must be re-titrated with a recheck at about one month. It is also a potent CYP3A4 INDUCER that lowers estrogen/progestin exposure, a classic cause of oral-contraceptive failure (a non-hormonal method is advised). Valproate is an enzyme INHIBITOR (it raises lamotrigine) and does not autoinduce or defeat contraception. Lamotrigine has no routine serum level and the interaction runs the opposite way — estrogen-containing pills LOWER lamotrigine (it does not lower the pill). Lithium is renally excreted with no CYP metabolism, so it neither autoinduces nor affects contraceptive efficacy.","meds":["lithium","carbamazepine","lamotrigine","valproate"],"focus":"drug interactions / autoinduction — the 3A4 inducer that self-lowers its level and causes OCP failure","tags":["comparison"],"source":{"name":"Carbamazepine product monograph (autoinduction; CYP3A4 induction)","origin":"monograph"},"answerId":"carbamazepine"},{"id":"boss_mood_5","stem":"A 29-year-old with bipolar II disorder has had three depressive episodes and no manic or hypomanic episodes requiring hospitalization. You want a maintenance agent that best prevents DEPRESSIVE relapse, accepting that it will not treat acute mania. Which agent is the preferred choice?","options":["Valproate","Carbamazepine","Gabapentin","Lamotrigine"],"answer":"Lamotrigine","explanation":"Lamotrigine is the maintenance stabilizer with the strongest role in bipolar DEPRESSION — it prevents depressive relapse but is NOT effective for acute mania, exactly matching a predominantly depressive bipolar II course. Valproate and carbamazepine are antimanic agents better suited to mania, mixed features, and rapid cycling, with weaker evidence for preventing depressive episodes. Gabapentin is NOT a primary mood stabilizer at all — it has negative bipolar RCTs and is used only adjunctively for anxiety, sleep, or pain — so it is the trap option here.","meds":["valproate","carbamazepine","gabapentin","lamotrigine"],"focus":"first-line for bipolar depression maintenance — the agent that prevents depressive relapse but not mania","tags":["comparison"],"source":{"name":"CANMAT bipolar disorder guidelines","origin":"canmat"},"answerId":"lamotrigine"}],"anxiolytics":[{"id":"boss_anxiolytics_1","stem":"A 58-year-old man with decompensated alcoholic cirrhosis (Child-Pugh C, elevated INR, ascites, mild encephalopathy) is admitted with anxiety and early alcohol-withdrawal symptoms and needs an oral benzodiazepine. Because his hepatic oxidative capacity is severely impaired, you want the agent least likely to accumulate — one cleared by direct glucuronidation with no oxidative CYP step and no active metabolite. Which is the best choice?","options":["Lorazepam","Diazepam","Chlordiazepoxide","Clonazepam"],"answer":"Lorazepam","explanation":"Lorazepam is conjugated by glucuronidation (UGT) to an inactive glucuronide with NO oxidative CYP step and no active metabolite, so its clearance is largely preserved in liver disease — one of the LOT benzodiazepines (Lorazepam, Oxazepam, Temazepam) preferred in hepatic impairment. Diazepam is the classic withdrawal agent but is oxidized (CYP2C19/3A4) to long-lived ACTIVE metabolites (nordiazepam, half-life up to ~200 h) that accumulate dangerously when hepatic oxidation fails. Chlordiazepoxide, another traditional withdrawal drug, is oxidatively metabolized to multiple active metabolites (including desmethyldiazepam) that likewise accumulate. Clonazepam depends on hepatic nitro-reduction and CYP3A4, so its clearance is also reduced in significant liver disease.","meds":["lorazepam","diazepam","chlordiazepoxide","clonazepam"],"focus":"LOT benzos safe in liver disease (lorazepam/oxazepam/temazepam) — glucuronidation, no active metabolite","tags":["comparison"],"source":{"name":"Product monographs (benzodiazepine metabolism)","origin":"monograph"},"answerId":"lorazepam"},{"id":"boss_anxiolytics_2","stem":"A 34-year-old woman with generalized anxiety disorder and a history of sedative and alcohol use disorder (now in recovery) needs long-term pharmacotherapy for chronic daily worry. She is worried about the abuse potential of prior treatments. You want a non-GABAergic anxiolytic with no dependence liability that must be taken on a fixed daily schedule — its benefit builds over weeks and it is ineffective when used as-needed. Which agent fits?","options":["Buspirone","Alprazolam","Lorazepam","Diazepam"],"answer":"Buspirone","explanation":"Buspirone is a 5-HT1A partial agonist with NO GABA-A/benzodiazepine activity, so it is non-sedating and non-dependence-forming; its anxiolytic effect builds over 1-2 weeks (full effect ~4 weeks), so it is dosed regularly BID-TID and is NOT effective PRN or for acute anxiety. Alprazolam, lorazepam, and diazepam are all GABA-A benzodiazepines (targeted substances) with dependence liability — alprazolam is the worst choice here given its rapid onset, short half-life, and prominent interdose rebound, exactly the reinforcement profile to avoid in a patient with sedative use disorder.","meds":["buspirone","alprazolam","lorazepam","diazepam"],"focus":"non-dependence-forming anxiolytic (buspirone) — 5-HT1A partial agonist, delayed onset, scheduled not PRN","tags":["comparison"],"source":{"name":"CANMAT anxiety guidelines","origin":"canmat"},"answerId":"buspirone"},{"id":"boss_anxiolytics_3","stem":"A patient with panic disorder is maintained on a short-half-life, high-potency benzodiazepine dosed three times daily but reports 'clock-watching' and rebound anxiety in the hours before each dose. You want to switch to an agent of similar high potency but with a LONG half-life and no significant active metabolite, so plasma levels stay steady and interdose rebound is minimized. Which is the best replacement?","options":["Clonazepam","Oxazepam","Triazolam","Midazolam"],"answer":"Clonazepam","explanation":"Clonazepam is a high-potency benzodiazepine with a long half-life (~18-50 h) and no significant active metabolite, giving stable plasma levels that smooth out the interdose rebound seen with short-acting, high-potency agents like alprazolam. Oxazepam is short-acting (~5-15 h) and low-potency, so it would not relieve the rebound problem. Triazolam (~1.5-5.5 h) and midazolam (~1.5-3 h) are ultra-short-acting and would markedly WORSEN interdose rebound; both are sleep-onset/sedation agents, not maintenance anxiolytics.","meds":["clonazepam","oxazepam","triazolam","midazolam"],"focus":"half-life/duration — long half-life smooths interdose rebound in panic disorder","tags":["comparison"],"source":{"name":"Product monographs (benzodiazepine pharmacokinetics)","origin":"monograph"},"answerId":"clonazepam"},{"id":"boss_anxiolytics_4","stem":"A 62-year-old with chronic insomnia marked by frequent middle-of-the-night awakenings (a sleep-MAINTENANCE problem, not just trouble falling asleep) has a prior history of hypnotic misuse and wants a non-controlled agent that is not dependence-forming yet improves BOTH sleep onset and maintenance. Which mechanism best matches these requirements?","options":["Daridorexant","Zolpidem","Ramelteon","Zopiclone"],"answer":"Daridorexant","explanation":"Daridorexant is a dual orexin receptor antagonist (DORA) that blocks OX1R/OX2R wake-promoting signalling, improving both sleep ONSET and MAINTENANCE; it is not a controlled substance, is non-dependence-forming, and its short half-life (~8 h) minimizes next-day impairment. Zolpidem (an alpha-1-selective imidazopyridine Z-drug, targeted substance) and zopiclone (a cyclopyrrolone Z-drug) both act at the benzodiazepine site and are dependence-forming — precisely the liability this patient wants to avoid — and zolpidem's very short half-life addresses onset more than maintenance. Ramelteon is a melatonergic MT1/MT2 agonist that is non-dependence-forming but targets sleep ONSET only, so it does not address the maintenance component.","meds":["daridorexant","zolpidem","ramelteon","zopiclone"],"focus":"orexin antagonist (DORA) vs Z-drug vs melatonergic — non-dependence + sleep maintenance","tags":["comparison"],"source":{"name":"Product monographs (hypnotic mechanisms)","origin":"monograph"},"answerId":"daridorexant"},{"id":"boss_anxiolytics_5","stem":"An anesthesiologist needs a benzodiazepine for conscious sedation immediately before a brief endoscopic procedure. The requirements: intravenous administration, onset within 1-3 minutes, an ultra-short duration so the patient recovers quickly afterward, and clinically useful anterograde amnesia. Which agent best meets all of these needs?","options":["Midazolam","Diazepam","Clonazepam","Temazepam"],"answer":"Midazolam","explanation":"Midazolam is an ultra-short-acting benzodiazepine (half-life ~1.5-3 h) available parenterally (IV/IM), with very rapid IV onset (1-3 min) and useful anterograde amnesia — the standard procedural-sedation agent. Diazepam also has rapid IV onset but a LONG effective half-life via long-lived active metabolites (nordiazepam up to ~200 h), causing prolonged sedation and slow recovery. Clonazepam is long-acting and has no parenteral formulation suited to this use. Temazepam is an oral hypnotic (glucuronidated, ~8-15 h) with no IV route and slower onset — unsuitable for acute procedural sedation.","meds":["midazolam","diazepam","clonazepam","temazepam"],"focus":"procedural sedation — ultra-short parenteral benzodiazepine (midazolam) with rapid onset and amnesia","tags":["comparison"],"source":{"name":"Midazolam product monograph","origin":"monograph"},"answerId":"midazolam"}],"adhd":[{"id":"boss_adhd_1","stem":"A 19-year-old university student meets criteria for ADHD and is motivated to start pharmacotherapy. He lives in a shared dormitory and discloses that last year a roommate crushed and snorted his previous stimulant. You want an agent that is least likely to produce a rapid \"high\" if it is insufflated or injected. Which stimulant is engineered as an inactive form that must be enzymatically hydrolyzed in the bloodstream before it becomes active, giving it the lowest liability for misuse by snorting or injection?","options":["Lisdexamfetamine","Amphetamine mixed salts","Dextroamphetamine","Methylphenidate"],"answer":"Lisdexamfetamine","explanation":"Lisdexamfetamine is an inactive prodrug — d-amphetamine covalently bound to L-lysine — that is hydrolyzed by red-blood-cell peptidases to active dextroamphetamine. Because conversion is rate-limited and happens in the blood, crushing and snorting or injecting it does not generate a fast euphoric surge, which blunts its misuse liability by those routes. Dextroamphetamine and Amphetamine mixed salts are already-active amphetamines that can be insufflated or injected for immediate effect, and Methylphenidate is likewise immediately active and misusable this way. All four are controlled drugs in Canada, but only the prodrug specifically defeats the snort/inject route.","meds":["lisdexamfetamine","amphetamine_salts","dextroamphetamine","methylphenidate"],"focus":"prodrug/abuse-liability (lisdexamfetamine) — inactive until hydrolyzed in blood, lowest diversion/insufflation risk among stimulants","tags":["comparison"],"source":{"name":"Lisdexamfetamine product monograph — prodrug activation & misuse","origin":"monograph"},"answerId":"lisdexamfetamine"},{"id":"boss_adhd_2","stem":"An 8-year-old with ADHD has a comorbid chronic tic disorder and marked sleep-onset insomnia. His parents decline controlled stimulants. You want a single non-controlled agent that can help daytime attention while also being sedating enough to give at bedtime to aid sleep onset and reduce tics. Which agent best matches all of these goals?","options":["Clonidine","Guanfacine","Atomoxetine","Methylphenidate"],"answer":"Clonidine","explanation":"Clonidine is a non-selective central α2-adrenergic agonist and the most sedating of the ADHD agents, which is exactly why it is favoured for comorbid tics and sleep-onset insomnia and is often dosed at bedtime. Guanfacine is also a non-stimulant α2 agonist useful for tics, but it is more α2A-selective and therefore less sedating, making it a weaker fit when bedtime sedation is specifically desired. Atomoxetine is non-controlled but is not sedating and has a delayed 2–4 week onset, so it does not address the sleep or tic problem the same way. Methylphenidate is a controlled stimulant that can worsen both tics and insomnia. Both α2 agonists must be tapered to avoid rebound hypertension, but only Clonidine matches the sedation-at-bedtime goal.","meds":["clonidine","guanfacine","atomoxetine","methylphenidate"],"focus":"alpha-2 agonist for tics/comorbid — clonidine's lower α2A-selectivity and greater sedation favour it over guanfacine for tics + sleep-onset insomnia","tags":["comparison"],"source":{"name":"CADDRA/CANMAT ADHD guidance — α2 agonists for tics and sleep","origin":"canmat"},"answerId":"clonidine"},{"id":"boss_adhd_3","stem":"A 30-year-old adult with ADHD and a history of stimulant misuse is started on a non-controlled medication. At a 6-day follow-up she reports no improvement in focus and asks to stop it, saying \"it isn't working.\" She confirms she has been taking it every day as prescribed. Which medication was most likely started — one whose therapeutic benefit characteristically emerges only over about 2 to 4 weeks rather than on the first day?","options":["Atomoxetine","Methylphenidate","Amphetamine mixed salts","Guanfacine"],"answer":"Atomoxetine","explanation":"Atomoxetine is a non-stimulant selective norepinephrine reuptake inhibitor; because it raises prefrontal norepinephrine and dopamine without the striatal dopamine surge that stimulants produce, its full benefit builds over roughly 2–4 weeks. A lack of effect at 6 days is therefore expected and is not treatment failure — she should continue. Methylphenidate and Amphetamine mixed salts are stimulants with same-day onset (behavioural effect within 30–60 minutes), so no benefit at all after correct dosing would be unusual — and both are controlled, which is a poor fit given her misuse history. Guanfacine is also non-controlled but its benefit emerges over about 1–2 weeks and it produces early sedation/blood-pressure effects; the classic 2–4 week delayed-onset profile in a patient chosen specifically to avoid a controlled agent points to atomoxetine.","meds":["atomoxetine","methylphenidate","amphetamine_salts","guanfacine"],"focus":"atomoxetine onset weeks — delayed 2–4 week benefit of the non-stimulant NRI vs same-day stimulant effect","tags":["comparison"],"source":{"name":"Atomoxetine product monograph — delayed onset of effect","origin":"monograph"},"answerId":"atomoxetine"},{"id":"boss_adhd_4","stem":"During teaching rounds, a pharmacology attending asks the group to identify the first-line ADHD stimulant that works purely by BLOCKING the dopamine and norepinephrine transporters to prevent reuptake — without entering the presynaptic neuron to reverse the transporters and trigger vesicular RELEASE of these transmitters. This release step is the mechanism that distinguishes the other options. Which agent is being described?","options":["Methylphenidate","Dextroamphetamine","Lisdexamfetamine","Amphetamine mixed salts"],"answer":"Methylphenidate","explanation":"Methylphenidate is a pure reuptake blocker at the dopamine and norepinephrine transporters (DAT/NET); it does not reverse the transporters or drive vesicular release. Dextroamphetamine, Lisdexamfetamine (which liberates dextroamphetamine after hydrolysis), and Amphetamine mixed salts all act primarily as releasers of dopamine and norepinephrine — entering the neuron and reversing transport — in addition to blocking reuptake. This release-versus-block contrast is the classic mechanistic distinction between methylphenidate and the amphetamine-class stimulants.","meds":["methylphenidate","dextroamphetamine","lisdexamfetamine","amphetamine_salts"],"focus":"MPH vs amphetamine mechanism — methylphenidate is a pure DAT/NET reuptake blocker whereas amphetamines are transmitter releasers","tags":["comparison"],"source":{"name":"Methylphenidate product monograph — reuptake-blockade mechanism","origin":"monograph"},"answerId":"methylphenidate"}],"substance":[{"id":"boss_substance_1","stem":"A 29-year-old man with opioid use disorder (daily IV fentanyl) comes to an office-based addiction clinic to begin opioid agonist therapy. He last used 16 hours ago; his COWS score is 14 with yawning, rhinorrhea, and dilated pupils. Guidelines favour a first-line, office-based agent whose partial mu-agonism gives a ceiling on respiratory depression, and it carries an abuse-deterrent component. The clinician stresses it must NOT be dosed until objective withdrawal is present, because its high receptor affinity will displace residual full agonist from the mu receptor and precipitate withdrawal. Which agent is being described?","options":["Buprenorphine/naloxone","Methadone","Naltrexone","Naloxone"],"answer":"Buprenorphine/naloxone","explanation":"The described agent is a high-affinity PARTIAL mu agonist with a ceiling on respiratory depression and an abuse-deterrent naloxone component (inert sublingually, but blocks the high and precipitates withdrawal if injected) — first-line OAT per CRISM. Its high mu affinity displaces full agonists, so it precipitates withdrawal unless started once the patient is in objective withdrawal (COWS). Methadone is a FULL mu agonist with NO ceiling; it does not precipitate withdrawal on induction this way — its induction danger is accumulation/overdose and QT, managed by start-low-go-slow. Naltrexone is a mu ANTAGONIST: it would precipitate withdrawal, requires a ~7-10 day opioid-free interval, and is not agonist maintenance. Naloxone is the short-acting acute overdose RESCUE antagonist, not a maintenance OAT.","meds":["buprenorphine_naloxone","methadone","naltrexone","naloxone"],"focus":"partial agonist / precipitated withdrawal — start OAT induction only in objective withdrawal","tags":["comparison"],"source":{"name":"Buprenorphine/naloxone product monograph","origin":"monograph"},"answerId":"buprenorphine_naloxone"},{"id":"boss_substance_2","stem":"A 47-year-old woman has been maintained on a full mu-opioid agonist for opioid use disorder, and her dose was recently raised to 130 mg/day. She presents after a syncopal episode. ECG shows QTc 510 ms, and she was started on a macrolide antibiotic last week. The team notes the agonist she is on has no ceiling on respiratory depression, a long and variable half-life prone to accumulation, and is a CYP3A4 substrate. Which opioid agonist therapy is she receiving?","options":["Methadone","Buprenorphine","Buprenorphine/naloxone","Naltrexone"],"answer":"Methadone","explanation":"Methadone is the FULL mu agonist OAT with dose-dependent QT prolongation and torsades de pointes — an ECG (baseline and follow-up, especially above 100 mg) is standard, and a QTc-prolonging macrolide compounds the risk. It has no ceiling on respiratory depression, a long/variable half-life that causes accumulation, and is a CYP3A4 substrate (inhibitors cause toxicity, inducers precipitate withdrawal). Buprenorphine and buprenorphine/naloxone are PARTIAL agonists with a ceiling and only minimal QT effect (less than methadone), so they would not fit this dose-dependent torsades picture. Naltrexone is a mu antagonist used for maintenance, not an agonist, and does not carry this QT profile.","meds":["methadone","buprenorphine","buprenorphine_naloxone","naltrexone"],"focus":"methadone QTc / torsades caution — dose-dependent, ECG monitoring, CYP3A4 full agonist","tags":["comparison"],"source":{"name":"Methadone product label","origin":"openfda"},"answerId":"methadone"},{"id":"boss_substance_3","stem":"A 58-year-old man with alcohol use disorder has been abstinent for 10 days and wants pharmacotherapy to MAINTAIN abstinence. He has Child-Pugh B alcoholic cirrhosis and takes daily oral morphine for chronic pancreatitis pain; his creatinine clearance is 85 mL/min. The clinician wants an anti-craving maintenance agent that is not hepatically metabolized, is non-aversive, and will not interfere with his opioid analgesia. Which agent best fits?","options":["Acamprosate","Naltrexone","Disulfiram","Naloxone"],"answer":"Acamprosate","explanation":"Acamprosate is excreted renally UNCHANGED and is not hepatically metabolized, making it a good choice in alcoholic liver disease; it is non-aversive, best at maintaining abstinence in an already-abstinent patient, and does not block opioids — its only key limit is severe renal impairment (contraindicated at CrCl less than or equal to 30 mL/min), and his renal function is fine. Naltrexone is wrong on two counts: it is hepatotoxic AND contraindicated in patients receiving opioid analgesics (it blocks their analgesia, precipitates withdrawal, and needs an opioid-free interval). Disulfiram is AVERSIVE rather than anti-craving and is hepatotoxic (can be fulminant) — poor in cirrhosis. Naloxone is the acute overdose rescue antagonist, not an AUD maintenance drug.","meds":["acamprosate","naltrexone","disulfiram","naloxone"],"focus":"naltrexone vs acamprosate for AUD — renal (not hepatic) clearance, non-aversive, and the opioid-free/opioid-analgesia requirement","tags":["comparison"],"source":{"name":"Acamprosate product monograph","origin":"monograph"},"answerId":"acamprosate"},{"id":"boss_substance_4","stem":"A 52-year-old man with alcohol use disorder is motivated, insightful, and fully abstinent, and specifically asks for a medication that will make him physically ill if he drinks, as an external deterrent. He is counselled to avoid ALL alcohol — including mouthwash, cough syrup, sauces, and hand sanitizer — because accumulating acetaldehyde causes flushing, throbbing headache, vomiting, and tachycardia, and that this reaction can occur up to about two weeks after the last dose. He is warned it must never be taken while intoxicated or without his knowledge, and baseline liver enzymes are drawn. Which agent is being prescribed?","options":["Disulfiram","Acamprosate","Naltrexone","Varenicline"],"answer":"Disulfiram","explanation":"Disulfiram IRREVERSIBLY inhibits aldehyde dehydrogenase, so drinking causes acetaldehyde to accumulate and produces the aversive disulfiram-alcohol reaction — it is the only AVERSIVE (not anti-craving) AUD agent, and because the enzyme block is irreversible the reaction can occur up to ~2 weeks after the last dose. It requires a motivated, abstinent patient, avoidance of all hidden alcohol sources, baseline/periodic LFTs (hepatotoxicity can be fulminant), and a boxed caution never to give it during intoxication or without the patient's knowledge. Acamprosate and naltrexone REDUCE craving rather than punishing drinking, so neither matches the aversive mechanism. Varenicline is a nicotinic partial agonist for smoking cessation and has nothing to do with alcohol aversion.","meds":["disulfiram","acamprosate","naltrexone","varenicline"],"focus":"disulfiram aversive mechanism (ALDH inhibition) & counselling — hidden alcohol, delayed reaction, LFTs","tags":["comparison"],"source":{"name":"Disulfiram product label","origin":"dailymed"},"answerId":"disulfiram"},{"id":"boss_substance_5","stem":"A 44-year-old woman with a 25-pack-year smoking history and a remote history of depression wants the single most effective pharmacotherapy to stop smoking. She is started on an oral agent about a week before her chosen quit date and warned to expect nausea and vivid, abnormal dreams, and to monitor for mood or behaviour changes. The clinician explains it is a partial agonist at the alpha-4-beta-2 nicotinic acetylcholine receptor: partial stimulation relieves craving while blocking nicotine's reward. Which agent is this?","options":["Varenicline","Buprenorphine","Naltrexone","Acamprosate"],"answer":"Varenicline","explanation":"Varenicline is an alpha-4-beta-2 nicotinic acetylcholine receptor PARTIAL agonist — the most effective single pharmacotherapy for smoking cessation. It is typically started ~1 week before the quit date; nausea and vivid/abnormal dreams are its hallmark side effects, and it carries a boxed warning to monitor for neuropsychiatric symptoms (the EAGLES trial was reassuring, but monitoring is still advised, especially with a psychiatric history). Buprenorphine is a mu-OPIOID partial agonist for opioid use disorder, not a nicotinic agent. Naltrexone (opioid antagonist for alcohol/opioid use disorder) and acamprosate (anti-craving for alcohol use disorder) do not target nicotine dependence.","meds":["varenicline","buprenorphine","naltrexone","acamprosate"],"focus":"varenicline for nicotine — alpha-4-beta-2 nicotinic partial agonist, smoking cessation","tags":["comparison"],"source":{"name":"Varenicline (Chantix) product label","origin":"dailymed"},"answerId":"varenicline"}],"dementia":[{"id":"boss_dementia_1","stem":"An 82-year-old woman with Alzheimer disease has been on a maximally titrated, well-tolerated cholinesterase inhibitor for 18 months. Her MMSE has fallen from 19 to 11 and she now needs help with dressing and toileting; her cardiologist confirms no bradyarrhythmia and she has no GI complaints. The team wants to ADD a second agent whose mechanism is distinct from her current drug and that can be safely combined with it to target this moderate-to-severe stage. Which agent should be added?","options":["Donepezil","Rivastigmine","Galantamine","Memantine"],"answer":"Memantine","explanation":"She is already on a cholinesterase inhibitor and has progressed into the moderate-to-severe range. Memantine is an uncompetitive NMDA-receptor antagonist — a mechanism entirely distinct from the cholinesterase inhibitors — so it is the agent indicated for moderate-to-severe disease and the one that can be added ON TOP of an existing cholinesterase inhibitor without overlapping cholinergic toxicity. Donepezil, rivastigmine and galantamine are all cholinesterase inhibitors; adding another one alongside her current drug simply doubles cholinergic (GI, bradycardic) load through the same mechanism rather than providing a complementary one, and galantamine is in any case restricted to mild-to-moderate Alzheimer.","meds":["donepezil","rivastigmine","galantamine","memantine"],"focus":"NMDA antagonist for moderate-severe / add-on to a cholinesterase inhibitor","tags":["comparison","dementia"],"source":{"name":"CANMAT/CCCDTD dementia pharmacotherapy — combination therapy and severity staging","origin":"canmat"},"answerId":"memantine"},{"id":"boss_dementia_2","stem":"A 76-year-old man with mild-to-moderate Alzheimer disease needs a cholinesterase inhibitor, but oral cholinergic therapy has repeatedly caused prominent nausea and vomiting during titration, and his daughter reports he frequently forgets his pills and sometimes hides them. The team wants a cholinesterase inhibitor in a formulation that delivers smoother drug levels to reduce GI side effects and lets the caregiver confirm adherence at a glance. Which agent uniquely offers this?","options":["Donepezil","Rivastigmine","Galantamine","Memantine"],"answer":"Rivastigmine","explanation":"Rivastigmine is the only agent here available as a transdermal patch, which produces smoother plasma levels than oral dosing, reduces the GI side effects that are limiting him, and lets the caregiver visually confirm the patch is on for adherence. Donepezil comes only as a tablet or orally-disintegrating tablet, galantamine only as an immediate-release tablet or extended-release capsule — neither has a patch. Memantine is not a cholinesterase inhibitor at all, comes only as a tablet, and is reserved for moderate-to-severe disease, so it does not fit this mild-to-moderate patient who needs cholinergic therapy in a better-tolerated delivery form.","meds":["donepezil","rivastigmine","galantamine","memantine"],"focus":"rivastigmine transdermal patch (GI tolerability and adherence)","tags":["comparison","dementia"],"source":{"name":"Rivastigmine monograph — transdermal patch formulation and GI tolerability","origin":"monograph"},"answerId":"rivastigmine"},{"id":"boss_dementia_3","stem":"A 70-year-old man with newly diagnosed mild Alzheimer disease lives alone with no caregiver supervision and is a poor historian who admits he 'sometimes goes a few days' without taking any medication. His cardiac workup and renal function are normal. The team wants to start a symptomatic cognitive agent whose long half-life makes it once-daily and forgiving of the occasional missed dose, without the risk that an interruption forces a restart at a lower dose. Which agent best fits?","options":["Donepezil","Rivastigmine","Galantamine","Memantine"],"answer":"Donepezil","explanation":"Donepezil has the longest half-life of the cholinesterase inhibitors, so it is dosed once daily and is forgiving of an occasional missed dose — ideal for an unsupervised patient with erratic adherence, and it is first-line across all stages including mild disease. Rivastigmine is the trap: after an interruption of more than about 3 days it must be restarted low and re-titrated, because resuming the prior dose risks severe vomiting — the opposite of forgiving. Galantamine has a shorter half-life, must be taken with food and fluids, and carries renal/hepatic dosing limits. Memantine is an NMDA antagonist reserved for moderate-to-severe disease and is not a first-line choice for this mild, treatment-naive patient.","meds":["donepezil","rivastigmine","galantamine","memantine"],"focus":"cholinesterase-inhibitor pharmacokinetics — donepezil long half-life and missed-dose tolerance vs rivastigmine re-titration","tags":["comparison","dementia"],"source":{"name":"Donepezil and rivastigmine monographs — half-life, dosing frequency, and re-titration after interruption","origin":"monograph"},"answerId":"donepezil"}],"adjunct":[{"id":"boss_adjunct_1","stem":"Ninety minutes after his second dose of intramuscular haloperidol for agitation, a 19-year-old man develops a painful, sustained upward and lateral deviation of both eyes, clenching of the jaw, and twisting of the neck. He is frightened but protecting his airway. Which agent, given intramuscularly, will most rapidly reverse this reaction?","options":["Benztropine","Amantadine","Valbenazine","Propranolol"],"answer":"Benztropine","explanation":"This is an acute dystonic reaction (oculogyric crisis with jaw and neck involvement) caused by D2 blockade acutely unbalancing striatal acetylcholine against dopamine; an intramuscular/intravenous central anticholinergic rebalances it within minutes, making benztropine the rescue agent. Amantadine is a dopaminergic/NMDA agent for drug-induced parkinsonism, not an acute-dystonia rescue, and works orally and slowly. Valbenazine is a VMAT2 inhibitor that further depletes dopamine (used for tardive dyskinesia, and US-only) — the wrong direction for a dystonia driven by dopamine blockade. Propranolol is first-line for akathisia, not for dystonia.","meds":["benztropine","amantadine","valbenazine","propranolol"],"focus":"acute dystonia → anticholinergic (IM/IV benztropine)","tags":["comparison"],"source":{"name":"Benztropine product monograph — acute dystonia / drug-induced EPS","origin":"monograph"},"answerId":"benztropine"},{"id":"boss_adjunct_2","stem":"A 34-year-old woman started on risperidone two weeks ago cannot stop moving — she paces constantly, rocks whenever she sits, and describes an unbearable inner restlessness she rates as worse than her psychosis. A trial of an oral anticholinergic gave no relief. She has no asthma, bradycardia, or heart block. Which agent is first-line for her condition?","options":["Propranolol","Trihexyphenidyl","Prazosin","Dexmedetomidine"],"answer":"Propranolol","explanation":"Her restlessness is antipsychotic-induced akathisia, for which a non-selective beta-blocker is first-line; the failed anticholinergic trial is a classic clue, because anticholinergics do not reliably relieve akathisia. Trihexyphenidyl is one such anticholinergic (useful for acute dystonia and parkinsonism, not akathisia, and it carries euphoriant misuse potential). Prazosin is an α1 antagonist for PTSD nightmares, not akathisia. Dexmedetomidine is an α2-agonist for acute agitation — a different target from the drug-induced restlessness of akathisia.","meds":["propranolol","trihexyphenidyl","prazosin","dexmedetomidine"],"focus":"antipsychotic-induced akathisia → propranolol (anticholinergics do not help)","tags":["comparison"],"source":{"name":"CANMAT / movement-disorder guidance — antipsychotic-induced akathisia","origin":"canmat"},"answerId":"propranolol"},{"id":"boss_adjunct_3","stem":"A 62-year-old man treated with a first-generation antipsychotic for over a decade develops persistent involuntary chewing, lip-smacking, and writhing tongue movements that continue even at rest. You practise in Canada and want an agent that will actually reduce the movements rather than worsen them. Which is the appropriate choice?","options":["Tetrabenazine","Deutetrabenazine","Procyclidine","Benztropine"],"answer":"Tetrabenazine","explanation":"These orofacial-lingual movements are tardive dyskinesia, driven by dopamine-receptor hypersensitivity after chronic D2 blockade; the treatment is a VMAT2 inhibitor, which depletes presynaptic dopamine and reduces the movements. In Canada the available VMAT2 inhibitor is tetrabenazine (Nitoman). Deutetrabenazine is also a VMAT2 inhibitor but is US-only (Austedo), so it is not the Canadian choice. Procyclidine and benztropine are anticholinergics — they treat acute dystonia and parkinsonism but WORSEN tardive dyskinesia by further unmasking dopamine hypersensitivity.","meds":["tetrabenazine","deutetrabenazine","procyclidine","benztropine"],"focus":"tardive dyskinesia → VMAT2 inhibitor (Canada-available tetrabenazine; anticholinergics worsen TD)","tags":["comparison"],"source":{"name":"Tetrabenazine (Nitoman) monograph — tardive dyskinesia; VMAT2 class","origin":"monograph"},"answerId":"tetrabenazine"},{"id":"boss_adjunct_4","stem":"A 41-year-old veteran with PTSD is stable on his SSRI by day but is jolted awake most nights by vivid combat nightmares, drenched in sweat with his heart pounding. He has no daytime hypotension. Which bedtime agent most specifically targets the trauma-related nightmares?","options":["Prazosin","Propranolol","Benztropine","Armodafinil"],"answer":"Prazosin","explanation":"PTSD nightmares reflect nocturnal noradrenergic surges; a bedtime α1-adrenergic antagonist blunts this and is the off-label go-to, so prazosin is correct (start low at bedtime and warn about the first-dose orthostatic hypotension). Propranolol is a beta-blocker used for akathisia, tremor, and adrenergic arousal, but it is not the specific nightmare agent and can itself cause vivid dreams and nightmares. Benztropine is an anticholinergic for EPS with no role here. Armodafinil is a wakefulness-promoting agent that would fragment sleep further — the wrong direction entirely.","meds":["prazosin","propranolol","benztropine","armodafinil"],"focus":"PTSD nightmares → prazosin (α1 antagonist)","tags":["comparison"],"source":{"name":"Prazosin monograph — α1 antagonism, first-dose orthostatic hypotension; PTSD-nightmare use","origin":"monograph"},"answerId":"prazosin"},{"id":"boss_adjunct_5","stem":"A 27-year-old with polysomnography-confirmed narcolepsy has irresistible daytime sleep attacks that disrupt her job despite good sleep hygiene. Working in a Canadian clinic, you want to start an approved wakefulness-promoting agent. Which do you prescribe?","options":["Modafinil","Armodafinil","Amantadine","Dexmedetomidine"],"answer":"Modafinil","explanation":"The excessive daytime sleepiness of narcolepsy is treated with a wakefulness-promoting agent; modafinil is approved and available in Canada for this indication (counsel about reduced oral-contraceptive efficacy from its CYP3A4 induction). Armodafinil is modafinil's longer-acting R-enantiomer but is US-only (Nuvigil), so it is not the Canadian choice. Amantadine is used for fatigue and drug-induced parkinsonism, not narcoleptic sleep attacks. Dexmedetomidine is a sedating α2-agonist for acute agitation — the opposite of a wakefulness agent.","meds":["modafinil","armodafinil","amantadine","dexmedetomidine"],"focus":"excessive daytime sleepiness / narcolepsy → modafinil (Canada-approved wakefulness agent)","tags":["comparison"],"source":{"name":"Modafinil product monograph — narcolepsy; CYP3A4 induction / contraceptive caveat","origin":"monograph"},"answerId":"modafinil"}]};
